async () => {
    console.log('[E2E] Etapa 1: aguardando questionario');
    await waitFor(element(by.id('input-peso-atual'))).toBeVisible().withTimeout(3000);
    console.log('[E2E] Etapa 2 e 3: preenchendo e enviando questionario');
    await fillQuestionnaireAndContinue();
    console.log('[E2E] Etapa 4: validando chegada na home');
    await waitFor(element(by.id('home-ready'))).toBeVisible().withTimeout(3000);
    console.log('[E2E] Etapa 5: navegando para treino');
    for (let attempt = 0; attempt < 4; attempt += 1) {
      const treinoVisible = await isVisibleById('tab-treino', 600);
      if (treinoVisible) {
        break;
      }
      await element(by.id('home-scroll')).swipe('up', 'fast', 0.6);
    }
    await waitFor(element(by.id('tab-treino'))).toBeVisible().withTimeout(3000);
    await element(by.id('tab-treino')).tap();
    const hasWorkoutHubCta = await isVisibleById('btn-iniciar-treino', 3000);
    if (hasWorkoutHubCta) {
      await element(by.id('btn-iniciar-treino')).tap();
    }
    console.log('[E2E] Etapa 6: preenchendo serie');
    await waitFor(element(by.id('input-peso'))).toBeVisible().withTimeout(3000);
    await waitFor(element(by.id('input-reps'))).toBeVisible().withTimeout(3000);
    await element(by.id('input-peso')).tap();
    await element(by.id('input-peso')).replaceText('80');
    await element(by.id('input-reps')).tap();
    await element(by.id('input-reps')).replaceText('10');
    await device.pressBack();
    console.log('[E2E] Etapa 7: salvando serie');
    await waitFor(element(by.id('btn-salvar-serie'))).toBeVisible().withTimeout(3000);
    await element(by.id('btn-salvar-serie')).tap();
    console.log('[E2E] Etapa 8: validando serie salva');
    await waitFor(element(by.id('serie-salva-indicator'))).toBeVisible().withTimeout(3000);
  }

